const items = $input.all();
const queries = items.map(item => {
  const d = item.json;
  return `INSERT INTO daily_trends (date, metric_name, metric_value)
    VALUES (CURRENT_DATE, '${d.metric}', ${d.val || 0})
    ON CONFLICT (date, metric_name) DO UPDATE SET
      metric_value = EXCLUDED.metric_value,
      rolling_avg_7d = (
        SELECT AVG(metric_value) FROM daily_trends
        WHERE metric_name = '${d.metric}'
        AND date >= CURRENT_DATE - 7
      ),
      rolling_avg_30d = (
        SELECT AVG(metric_value) FROM daily_trends
        WHERE metric_name = '${d.metric}'
        AND date >= CURRENT_DATE - 30
      );`;
});
return [{json: {query: queries.join('\n'), count: queries.length}}];
